import React, { useState } from "react";
import "./Men.css";

const womenProducts = [
  { id: 1, name: "Women Casual Dress", price: 45, image: "/images/women/women1.jpg" },
  { id: 2, name: "Women Formal Dress", price: 65, image: "/images/women/women2.jpg" },
  { id: 3, name: "Women Top", price: 35, image: "/images/women/women3.jpg" },
  { id: 4, name: "Women Jacket", price: 80, image: "/images/women/women4.jpg" },
  { id: 5, name: "Women Skirt", price: 40, image: "/images/women/women5.jpg" },
  { id: 6, name: "Women Hoodie", price: 70, image: "/images/women/women6.jpg" },
  { id: 7, name: "Women Hoodie", price: 70, image: "/images/women/women7.jpg" },
  { id: 8, name: "Women Hoodie", price: 70, image: "/images/women/women8.jpg" },
  


];

const Women = () => {
  const [qty, setQty] = useState({});

  const inc = (id) => setQty({ ...qty, [id]: (qty[id] || 0) + 1 });
  const dec = (id) => setQty({ ...qty, [id]: Math.max((qty[id] || 0) - 1, 0) });

  return (
    <div className="men-page">
      <h2 className="men-title">Women Collection</h2>

      <div className="men-grid">
        {womenProducts.map((item) => (
          <div className="men-card" key={item.id}>
            <div className="men-img-box">
              <img src={item.image} alt={item.name} />
            </div>

            <div className="men-info">
              <h3>{item.name}</h3>
              <p className="price">${item.price}</p>

              <div className="qty-box">
                <button onClick={() => dec(item.id)}>-</button>
                <span>{qty[item.id] || 0}</span>
                <button onClick={() => inc(item.id)}>+</button>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Women;
